using Microsoft.AspNetCore.Authorization;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments");

        // Get all shipments (dispatchers)
        group.MapGet("/", [Authorize] async (ApplicationDbContext db) =>
        {
            var shipments = await db.Shipments
                .OrderByDescending(s => s.CreatedAt)
                .Select(s => new ShipmentDto
                {
                    Id = s.Id,
                    TrackingNumber = s.TrackingNumber,
                    Origin = s.Origin,
                    Destination = s.Destination,
                    Status = s.Status,
                    CreatedAt = s.CreatedAt,
                    EstimatedDelivery = s.EstimatedDelivery,
                    RecipientName = s.RecipientName,
                    SenderName = s.SenderName,
                    Notes = s.Notes
                })
                .ToListAsync();

            return Results.Ok(shipments);
        });

        // Track a shipment by tracking number (public)
        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments
                .Where(s => s.TrackingNumber == trackingNumber)
                .Select(s => new ShipmentDto
                {
                    Id = s.Id,
                    TrackingNumber = s.TrackingNumber,
                    Origin = s.Origin,
                    Destination = s.Destination,
                    Status = s.Status,
                    CreatedAt = s.CreatedAt,
                    EstimatedDelivery = s.EstimatedDelivery,
                    RecipientName = s.RecipientName,
                    SenderName = s.SenderName,
                    Notes = s.Notes
                })
                .FirstOrDefaultAsync();

            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        });

        // Create a shipment (dispatchers)
        group.MapPost("/", [Authorize] async (CreateShipmentRequest request, ApplicationDbContext db) =>
        {
            var shipment = new Shipment
            {
                TrackingNumber = GenerateTrackingNumber(),
                Origin = request.Origin,
                Destination = request.Destination,
                Status = ShipmentStatus.Pending,
                CreatedAt = DateTime.UtcNow,
                EstimatedDelivery = request.EstimatedDelivery,
                RecipientName = request.RecipientName,
                SenderName = request.SenderName,
                Notes = request.Notes
            };

            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();

            return Results.Created($"/api/shipments/{shipment.Id}", new ShipmentDto
            {
                Id = shipment.Id,
                TrackingNumber = shipment.TrackingNumber,
                Origin = shipment.Origin,
                Destination = shipment.Destination,
                Status = shipment.Status,
                CreatedAt = shipment.CreatedAt,
                EstimatedDelivery = shipment.EstimatedDelivery,
                RecipientName = shipment.RecipientName,
                SenderName = shipment.SenderName,
                Notes = shipment.Notes
            });
        });

        // Update shipment status (dispatchers)
        group.MapPut("/{id:int}/status", [Authorize] async (int id, UpdateShipmentStatusRequest request, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            shipment.Status = request.Status;
            if (request.Notes is not null)
                shipment.Notes = request.Notes;

            await db.SaveChangesAsync();

            return Results.Ok(new ShipmentDto
            {
                Id = shipment.Id,
                TrackingNumber = shipment.TrackingNumber,
                Origin = shipment.Origin,
                Destination = shipment.Destination,
                Status = shipment.Status,
                CreatedAt = shipment.CreatedAt,
                EstimatedDelivery = shipment.EstimatedDelivery,
                RecipientName = shipment.RecipientName,
                SenderName = shipment.SenderName,
                Notes = shipment.Notes
            });
        });
    }

    private static string GenerateTrackingNumber()
    {
        return $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Guid.NewGuid().ToString()[..8].ToUpperInvariant()}";
    }
}

