arguments.new_str:
@page "/"

<PageTitle>Track Your Shipment</PageTitle>

<h1>Shipment Tracker</h1>
<p class="lead">Enter your tracking number to check your shipment status and estimated delivery.</p>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="e.g. SHP-20260501-A1B2C3D4"
                   @bind="trackingNumber" @bind:event="oninput"
                   @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="TrackShipment" disabled="@isLoading">
                @if (isLoading)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Track
            </button>
        </div>
    </div>
</div>

@if (errorMessage is not null)
{
    <div class="alert alert-warning">@errorMessage</div>
}

@if (shipment is not null)
{
    <div class="card">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@shipment.TrackingNumber</strong>
            <span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <p><strong>From:</strong> @shipment.Origin</p>
                    <p><strong>To:</strong> @shipment.Destination</p>
                    <p><strong>Sender:</strong> @shipment.SenderName</p>
                    <p><strong>Recipient:</strong> @shipment.RecipientName</p>
                </div>
                <div class="col-md-6">
                    <p><strong>Shipped:</strong> @shipment.CreatedAt.ToString("MMM dd, yyyy")</p>
                    <p><strong>Estimated Delivery:</strong>
                        @if (shipment.EstimatedDelivery.HasValue)
                        {
                            @shipment.EstimatedDelivery.Value.ToString("MMM dd, yyyy")
                        }
                        else
                        {
                            <span class="text-muted">TBD</span>
                        }
                    </p>
                    @if (shipment.Notes is not null)
                    {
                        <p><strong>Notes:</strong> @shipment.Notes</p>
                    }
                </div>
            </div>

            <div class="mt-3">
                <h6>Delivery Progress</h6>
                <div class="progress" style="height: 25px;">
                    <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                         role="progressbar"
                         style="width: @(GetProgressPercent(shipment.Status))%">
                        @shipment.Status
                    </div>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private ShipmentDto? shipment;
    private string? errorMessage;
    private bool isLoading;

    [Inject] private HttpClient Http { get; set; } = default!;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isLoading = true;
        errorMessage = null;
        shipment = null;

        try
        {
            var response = await Http.GetAsync($"api/shipments/track/{Uri.EscapeDataString(trackingNumber.Trim())}");
            if (response.IsSuccessStatusCode)
            {
                shipment = await response.Content.ReadFromJsonAsync<ShipmentDto>();
            }
            else
            {
                errorMessage = "Shipment not found. Please check your tracking number and try again.";
            }
        }
        catch
        {
            errorMessage = "Unable to reach the server. Please try again later.";
        }
        finally
        {
            isLoading = false;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Cancelled => 100,
        _ => 0
    };
}

