arguments.file_text:
@page "/dispatch"
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Dispatcher Dashboard</h1>

<div class="d-flex justify-content-between align-items-center mb-3">
    <div class="input-group" style="max-width: 350px;">
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" />
        <button class="btn btn-outline-secondary" @onclick="ClearFilter">Clear</button>
    </div>
    <button class="btn btn-success" @onclick="ShowCreateForm">
        + New Shipment
    </button>
</div>

@if (showCreate)
{
    <div class="card mb-4">
        <div class="card-header">Create New Shipment</div>
        <div class="card-body">
            <EditForm Model="newShipment" OnValidSubmit="CreateShipment" FormName="createShipment">
                <DataAnnotationsValidator />
                <div class="row g-3">
                    <div class="col-md-6">
                        <label class="form-label">Origin</label>
                        <InputText class="form-control" @bind-Value="newShipment.Origin" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Destination</label>
                        <InputText class="form-control" @bind-Value="newShipment.Destination" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Sender Name</label>
                        <InputText class="form-control" @bind-Value="newShipment.SenderName" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Recipient Name</label>
                        <InputText class="form-control" @bind-Value="newShipment.RecipientName" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Estimated Delivery</label>
                        <InputDate class="form-control" @bind-Value="newShipment.EstimatedDelivery" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Notes</label>
                        <InputText class="form-control" @bind-Value="newShipment.Notes" />
                    </div>
                    <div class="col-12">
                        <button type="submit" class="btn btn-primary me-2" disabled="@isCreating">
                            @if (isCreating)
                            {
                                <span class="spinner-border spinner-border-sm me-1"></span>
                            }
                            Create Shipment
                        </button>
                        <button type="button" class="btn btn-secondary" @onclick="CancelCreate">Cancel</button>
                    </div>
                </div>
            </EditForm>
        </div>
    </div>
}

@if (errorMessage is not null)
{
    <div class="alert alert-danger alert-dismissible">
        @errorMessage
        <button type="button" class="btn-close" @onclick="() => errorMessage = null"></button>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <p class="text-muted">No shipments match your filter.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Recipient</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in FilteredShipments)
                {
                    <tr>
                        <td><code>@s.TrackingNumber</code></td>
                        <td>@s.Origin</td>
                        <td>@s.Destination</td>
                        <td>@s.RecipientName</td>
                        <td><span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span></td>
                        <td>@(s.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "TBD")</td>
                        <td>
                            @if (s.Status != ShipmentStatus.Delivered && s.Status != ShipmentStatus.Cancelled)
                            {
                                <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                        @onchange="(e) => UpdateStatus(s.Id, e)">
                                    <option value="">Change status...</option>
                                    @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                    {
                                        if (status != s.Status)
                                        {
                                            <option value="@((int)status)">@status</option>
                                        }
                                    }
                                </select>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = string.Empty;
    private string? errorMessage;
    private bool showCreate;
    private bool isCreating;
    private CreateShipmentRequest newShipment = new();

    [Inject] private HttpClient Http { get; set; } = default!;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        shipments?.Where(s =>
            string.IsNullOrWhiteSpace(filterText) ||
            s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase))
        ?? Enumerable.Empty<ShipmentDto>();

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        try
        {
            shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("api/shipments");
        }
        catch
        {
            errorMessage = "Failed to load shipments.";
        }
    }

    private void ShowCreateForm() => showCreate = true;
    private void CancelCreate()
    {
        showCreate = false;
        newShipment = new();
    }

    private void ClearFilter() => filterText = string.Empty;

    private async Task CreateShipment()
    {
        isCreating = true;
        try
        {
            var response = await Http.PostAsJsonAsync("api/shipments", newShipment);
            if (response.IsSuccessStatusCode)
            {
                showCreate = false;
                newShipment = new();
                await LoadShipments();
            }
            else
            {
                errorMessage = "Failed to create shipment.";
            }
        }
        catch
        {
            errorMessage = "Unable to reach the server.";
        }
        finally
        {
            isCreating = false;
        }
    }

    private async Task UpdateStatus(int id, ChangeEventArgs e)
    {
        if (e.Value is not string val || !int.TryParse(val, out var statusInt)) return;

        var request = new UpdateShipmentStatusRequest { Status = (ShipmentStatus)statusInt };
        try
        {
            var response = await Http.PutAsJsonAsync($"api/shipments/{id}/status", request);
            if (response.IsSuccessStatusCode)
            {
                await LoadShipments();
            }
            else
            {
                errorMessage = "Failed to update shipment status.";
            }
        }
        catch
        {
            errorMessage = "Unable to reach the server.";
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

